sp_header_footer.client_script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
function taskerFooterCtrl($scope, spModal, $window, $location) {
    /* widget controller */
    var c = this;

    showLegalNotice();

    function showLegalNotice() {

        if (c.data.showLegalNotice == true || c.data.showAcknowledgement == true) {
            spModal.open({
                backdrop: 'static',
                title: c.data.lnCaption,
                message: c.data.lnModalMessage,
                buttons: [{
                    label: c.data.lnModalOkButton,
                    primary: true
                }],
                size: 'lg'
            }).then(function() {
                c.data.answer = true;
                c.data.saveLegalNotice = c.data.showLegalNotice;
                c.data.saveAcknowledgement = c.data.showAcknowledgement;
                refreshWidget();

            }, function() {
                c.data.answer = false;
								// STRY0113838
                $window.location = $scope.portal.url_suffix;
            });
        }
    }

    function refreshWidget(evt, arg) {
        //c.server.refresh(); 
        c.server.update();
    }
}

sp_header_footer.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
/* Special License Rights
 *  The Government's rights to use, display, or disclose this software are restricted.
 *  Any reproduction of computer software, computer software documentation,
 *  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: 
//------------------------------------------------------------------------------------------------------------------------
// 10.02.2020 | KT | Updated ONLY for DIA
// 02.24.2021 | mmcc | Customizable process for any customer admin to setup a legal notice or Acknowledgement
// 2.7.0 | 2021-10-23 | mmcc | STRY0110517 - Tasker Settings- IP/Copyright Footer 
//											In HTML, added an ng-if to display or hide the footer div
//											In Service script, added isFooterMessageShown()
//                                          Changes in HTML and Server script
//
// 2.7.0 | 2021-11-16 | raj  | STRY0113838 - Tasker Settings- Allow for custom "URL Suffix" for Tasker Portal
//											In Client Controller
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data) {
    // Always use the most recent timestamp
    var gdtNewUserPreference = new GlideDateTime();

    // User Preferences name where the last legal notice UTC date-time is stored as a string
    var strPreferenceNameLegalNotice = 'DTechApps.Tasker.AccessAcknowledgementLegal';

    // User Preferences name where the last acknowledgement UTC date-time is stored as a string
    var strPreferenceNameAcknowledgement = 'DTechApps.Tasker.AccessAcknowledgement';
    var strUserAcknowledgementValue = gs.getUser().getPreference(strPreferenceNameAcknowledgement);
    var gdtCurrentAcknowledgement = getCurrentAcknowledgementDateTime(strUserAcknowledgementValue);

    main();


    function main() {

        if (input) {
            if (input.answer == true) {
                if (input.saveLegalNotice) {
                    // Save the Legal NOtice string version of the DateTime
                    gs.getUser().savePreference(strPreferenceNameLegalNotice, gdtNewUserPreference.getValue());
                    // gs.info('  *** Footer save Legal Notice Preference gdtNewUserPreference: {0}', gdtNewUserPreference.getValue());
                }

                if (input.saveAcknowledgement) {
                    // Save the Acknowledgement string version of the DateTime
                    gs.getUser().savePreference(strPreferenceNameAcknowledgement, gdtNewUserPreference.getValue());
                    gs.getSession().putClientData('user_pref_ack', gdtNewUserPreference.getValue());
                    // gs.info('  *** Footer save Acknowledgement Preference gdtNewUserPreference: {0}', gdtNewUserPreference.getValue());
                }
            }
        } else {
            if (isAnyEventShown()) {
                getTaskerSettingsForModal();
            }
        }
    }

    function isAnyEventShown() {
        data.showLegalNotice = isLegalNoticeMessageShown();
        data.showAcknowledgement = isAcknowledgementMessageShown();

		// 2.7.0 | 2021-10-23 | mmcc | STRY0110517 - Tasker Settings- IP/Copyright Footer
		data.showFooter = isFooterMessageShown();

        return (data.showLegalNotice || data.showAcknowledgement);
    }

    function isAcknowledgementMessageShown() {
        // Get the Choices: Never=0, Daily=1, Per log in=2, First log in=3
        var acknowledgementEvent = +gs.getProperty('x_153465_discovert.AcknowledgementEvent');
        var showAcknowledgementMessage = false;

        switch (acknowledgementEvent) {
            case 3:
                // First log in
                showAcknowledgementMessage = showFirstLogIn('ackno');
                break;
            case 2:
                // Per log in
                showAcknowledgementMessage = showPerLogInAcknowledgement();
                break;
            case 1:
                // Daily
                showAcknowledgementMessage = showDailyAcknowledgement();
                break;
            default:
                // case Never
                showAcknowledgementMessage = false;
        }

        return showAcknowledgementMessage;
    }

	// 2.7.0 | 2021-10-23 | mmcc | STRY0110517 - Tasker Settings- IP/Copyright Footer
	// Use this function to get the System Property that controls display/hide of the footer message
	function isFooterMessageShown() {
        // Get the Choices: Display Footer=0, Hide Footer=1
        var taskerFooterOption = +gs.getProperty('x_153465_discovert.TaskerFooterOptions');
        var showFooterMessage = true;

        switch (taskerFooterOption) {
            case 1:
                // Hide Footer
                showFooterMessage = false;
                break;
            default:
                // case Display Footer
                showFooterMessage = true;
        }

        return showFooterMessage;
    }

    function isLegalNoticeMessageShown() {
        // Get the Choices: Never, First log in
        var legalNoticeEvent = gs.getProperty('x_153465_discovert.LegalNoticeEvent').replace(/ /g, '').toUpperCase();

        var showLegalNoticeMessage = false;

        if (legalNoticeEvent === 'FIRSTLOGIN') {
            showLegalNoticeMessage = showFirstLogIn('legal');
        }

        return showLegalNoticeMessage;
    }

    function getTaskerSettingsForModal() {
        data.lnCaption = gs.getMessage('Tasker - AcknowledgementCaption');
        data.lnModalOkButton = gs.getMessage('Tasker - AcknowledgementModalOkButton');
        data.lnModalMessage = '';

        // build up the html for showing the logo; best practice is to use HTML Semantic Elements, no div's
        var logoPart1 = '<section><img src="';
        var logoPart2 = gs.getProperty('x_153465_discovert.AcknowledgementLogo');
        var logoPart3 = '" class="img-responsive center-block"/></section><br>';

        // Should look like: <section><img src="tasker_logo.png" class="img-responsive center-block"/></section>
        var fullLogo = logoPart1.concat(logoPart2, logoPart3);
        // if a logo was not selected then do not add it to the output
        if (logoPart2 && logoPart2.length > 0) {
            data.lnModalMessage = data.lnModalMessage.concat(fullLogo);
        }

        if (data.showLegalNotice) {
            data.lnModalMessage = data.lnModalMessage.concat(gs.getMessage('Tasker - LegalNoticeModalMessage'));
        }

        if (data.showAcknowledgement) {
            data.lnModalMessage = data.lnModalMessage.concat(gs.getMessage('Tasker - AcknowledgementModalMessage'));
        }
    }

    function showDailyAcknowledgement() {
        var isShowing = false;

        var gdToday = new GlideDate();
        gdToday = gdtNewUserPreference.getDate();

        // Get User Preference date part as UTC
        var gdPrefDate = new GlideDate();
        gdPrefDate = gdtCurrentAcknowledgement.getDate();

        // Compare the 2 date parts
        if (gdPrefDate.equals(gdToday) == false) {
            isShowing = true;
        }

        return isShowing;
    }

    function showPerLogInAcknowledgement() {
        var isShowing = true;

        if (gs.getSession().getClientData('user_pref_ack')) {
            isShowing = false;
        }

        return isShowing;
    }

    function showFirstLogIn(promptType) {
        var isShowing = false;
        var strUserPreferenceValue = gs.getUser().getPreference(strPreferenceNameAcknowledgement);

        if (promptType === 'legal') {
            strUserPreferenceValue = gs.getUser().getPreference(strPreferenceNameLegalNotice);
        }

        var gdtCurrentPreference = new GlideDateTime();
        gdtCurrentPreference.setValue(strUserPreferenceValue);

        // Check for bad data since the Admin can edit it - make blank, any free text or missed typed DateTime
        if (gdtCurrentPreference.isValid() == false || (gdtCurrentPreference.hasDate() == false)) {
            isShowing = true;
        } else if (gdtCurrentPreference.onOrAfter(gdtNewUserPreference)) {
            // Case when Admin sets a DateTime in the future
            isShowing = true;
        }

        return isShowing;
    }

    function getCurrentAcknowledgementDateTime(strUserPref) {
        var gdtCurrPref = new GlideDateTime();
        gdtCurrPref.setValue(strUserPref);

        // Check for bad data since the Admin can edit it - make blank, any free text or missed typed DateTime
        if (gdtCurrPref.isValid() == false || (gdtCurrPref.hasDate() == false)) {
            gdtCurrPref.setValue(gs.yesterday());
        }

        return gdtCurrPref;
    }

})($sp, input, data);
